using json = nlohmann::json;
class Validator1 {
public:
    struct Result { bool valid=true; std::string message,field; std::vector<std::string> errors; json toJson() const { json j;j["valid"]=valid;if(!valid){j["message"]=message;j["field"]=field;if(!errors.empty())j["errors"]=errors;}return j; } };
    Result validate(const json& data) {
        Result r; r.field="field1";
        if(!data.contains("name")) { r.valid=false; r.message="Field 'name' is required"; return r; }
        std::string name=data["name"];
        if(name.empty()) { r.valid=false; r.message="Name cannot be empty"; return r; }
        if(name.size()>255) { r.valid=false; r.message="Name exceeds max length of 255"; return r; }
        if(data.contains("email")) { std::string e=data["email"]; if(e.find('@')==std::string::npos){r.valid=false;r.message="Invalid email format";r.errors.push_back("email_invalid");} }
        if(data.contains("age")) { int a=data["age"]; if(a<0||a>150){r.valid=false;r.message="Age out of range [0-150]";} }
        if(data.contains("url")) { std::string u=data["url"]; if(u.find("http")!=0){r.valid=false;r.message="URL must start with http";} }
        if(data.contains("amount")) { double a=data["amount"]; if(a<0){r.valid=false;r.message="Amount cannot be negative";} }
        if(data.contains("count")) { int c=data["count"]; if(c<0){r.valid=false;r.message="Count cannot be negative";} }
        return r;
    }
    Result validateRequired(const json& data,const std::string& field) { Result r;r.field=field;if(!data.contains(field)||data[field].is_null()){r.valid=false;r.message=field+" is required";}return r; }
    Result validateMinLength(const std::string& val,size_t min,const std::string& field) { Result r;r.field=field;if(val.size()<min){r.valid=false;r.message=field+" must be at least "+std::to_string(min)+" characters";}return r; }
    Result validateMaxLength(const std::string& val,size_t max,const std::string& field) { Result r;r.field=field;if(val.size()>max){r.valid=false;r.message=field+" exceeds max length of "+std::to_string(max);}return r; }
};
